async (params, browser) => {
  // Open Transfermarkt
  await browser.open(`https://www.transfermarkt.com/${params.player_path}`)

  // Wait for page
  await browser.waitForSelector('h1.data-header__headline-wrapper, .data-header, .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const headerEl = document.querySelector('h1.data-header__headline-wrapper'); const name = headerEl ? Array.from(headerEl.childNodes).filter(n => n.nodeType === 3 || n.tagName === 'STRONG').map(n => n.textContent.trim()).filter(Boolean).join(' ') : ''; const info = {}; const fields = ['Name in home country','Full name','Date of birth/Age','Place of birth','Height','Citizenship','Position','Foot','Player agent','Current club','Joined','Contract expires','Outfitter']; for (const field of fields) { const labelSpan = Array.from(document.querySelectorAll('span')).find(s => s.textContent.trim().startsWith(field)); if (labelSpan) { const valueSpan = labelSpan.nextElementSibling; if (valueSpan) { const imgs = valueSpan.querySelectorAll('img.flaggenrahmen'); if (imgs.length > 0) { info[field.toLowerCase().replace(/\//g,'_')] = Array.from(imgs).map(img => img.getAttribute('title')).join(', '); } else { info[field.toLowerCase().replace(/\//g,'_')] = valueSpan.textContent.trim(); } } } } const birthEl = document.querySelector('span[itemprop="birthDate"]'); if (birthEl) info['date_of_birth'] = birthEl.textContent.trim(); const shirtEl = document.querySelector('span.data-header__shirt-number'); if (shirtEl) info['shirt_number'] = shirtEl.textContent.trim(); const clubEl = document.querySelector('span.data-header__club a'); if (clubEl) info['current_club'] = clubEl.textContent.trim(); const value = document.querySelector('a.data-header__market-value-wrapper')?.textContent?.trim()?.replace(/\s+/g,' ') || document.querySelector('.tm-player-market-value-development__current-value')?.textContent?.trim() || ''; const imgEl = document.querySelector('img.data-header__profile-image'); const image = imgEl?.getAttribute('src') || ''; return { name, info, market_value: value, image, url: window.location.href };`)

  return result
}
